svg.text:
Using parallelogram perimeter for progressive drawing
Script
// we draw parallelogram as path element
node = evt.target.ownerDocument.getElementById('parallelo')
// For path we can know perimeter with getTotalLength()
// Calcul of perimeter
perimeter = node.getTotalLength()
// Affect this value for stroke-dasharray and stroke-dashoffset
node.setAttributeNS(null , 'stroke-dasharray' , perimeter.toString() + " " + perimeter.toString() )
node.setAttributeNS(null , 'stroke-dashoffset' , perimeter.toString() )
// Affect this value for from in animate element
evt.target.ownerDocument.getElementById('anime1').setAttributeNS(null , 'from' , perimeter.toString() )
SVG objects
<path id="parallelo" d="M200 340l250 50 50 150 -250 -50z" stroke="blue" fill="lime" fill-opacity="0" >
<animate id="anime1" attributeName="stroke-dashoffset" to="0" dur="5s" begin="go.click" fill="freeze"/>
</path>
